pub fn compute_function_fingerprint(source_text: &str, analysis: &FunctionAnalysis) -> String {
    let mut hasher = Sha256::new();

    // Hash source text
    hasher.update(b"source:");
    hasher.update(source_text.as_bytes());

    // Hash parameters (sorted by name)
    let mut params: Vec<_> = analysis.params.iter()...collect();
    params.sort();
    hasher.update(b"params:");
    for p in &params { ... }

    // Hash branch structure (sorted by ID)
    let mut branches: Vec<_> = analysis.branches.iter()...collect();
    branches.sort();
    hasher.update(b"branches:");
    for b in &branches { ... }

    format!("{:x}", hasher.finalize())
}
```

