fn cli_parses_explore_with_clean_flag() {
    let cli = Cli::parse_from([
        "shatter",
        "explore",
        "--clean",
        "test.ts:myFunc",
    ]);
    match cli.command {
        CliCommand::Explore { clean, dry_run, .. } => {
            assert!(clean);
            assert!(!dry_run);
        }
        _ => panic!("expected Explore command"),
    }
}

#[test]
fn cli_parses_explore_with_dry_run_flag() {
    let cli = Cli::parse_from([
        "shatter",
        "explore",
        "--dry-run",
        "--output", "spec.json",
        "test.ts:myFunc",
    ]);
    match cli.command {
        CliCommand::Explore { clean, dry_run, output, .. } => {
            assert!(!clean);
            assert!(dry_run);
            assert_eq!(output, Some(PathBuf::from("spec.json")));
        }
        _ => panic!("expected Explore command"),
    }
}

#[test]
fn cli_clean_and_dry_run_default_to_false() {
    let cli = Cli::parse_from([
        "shatter",
        "explore",
        "test.ts:myFunc",
    ]);
    match cli.command {
        CliCommand::Explore { clean, dry_run, .. } => {
            assert!(!clean);
            assert!(!dry_run);
        }
        _ => panic!("expected Explore command"),
    }
}

